Pausa — a estrutura acima está colapsando o closure erroneamente. Redesenhando:

```typescript
// src/discount.ts

export type DiscountType = 'percentage' | 'fixed';

export interface Discount {
  type: DiscountType;
  value: number;
}

// Ponto de extensão: registre novos tipos aqui.
const discountStrategies: Record<string, (price: number, value: number) => number> = {
  percentage: (price, value) => price * (1 - value / 100),
  fixed: (price, value) => price - value,
};

export function registerDiscount(
  type: string,
  fn: (price: number, value: number) => number,
): void {
  discountStrategies[type] = fn;
}

export function applyDiscount(price: number, discount: Discount): number {
  if (price < 0) throw new RangeError('price must be >= 0');
  if (discount.value < 0) throw new RangeError('discount.value must be >= 0');

  const strategy = discountStrategies[discount.type];
  if (!strategy) throw new TypeError(`Unknown discount type: "${discount.type}"`);

  return Math.max(0, strategy(price, discount.value));
}
```

