// src/utils/discount.ts

type DiscountType = "percentage" | "fixed";

export function calculateDiscount(
  price: number,
  discount: number,
  type: DiscountType = "percentage"
): number {
  if (price < 0 || discount < 0) throw new Error("price and discount must be non-negative");

  switch (type) {
    case "percentage":
      if (discount > 100) throw new Error("percentage discount cannot exceed 100");
      return price * (1 - discount / 100);
    case "fixed":
      return Math.max(0, price - discount);
  }
}
```

